class LibraryCardModel {
  final String id;
  final String title;
  final String body;

  LibraryCardModel({
    required this.id,
    required this.title,
    required this.body,
  });
}

class LibraryModuleModel {
  final int workoutIndex;
  final List<LibraryCardModel> cards;

  LibraryModuleModel({
    required this.workoutIndex,
    required this.cards,
  });
}

